package com.cybersecuals.gridgarrison.trust.contract;

import io.reactivex.Flowable;
import java.math.BigInteger;
import java.util.Arrays;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import org.web3j.abi.EventEncoder;
import org.web3j.abi.FunctionEncoder;
import org.web3j.abi.TypeReference;
import org.web3j.abi.datatypes.Address;
import org.web3j.abi.datatypes.Event;
import org.web3j.abi.datatypes.Function;
import org.web3j.abi.datatypes.Type;
import org.web3j.abi.datatypes.Utf8String;
import org.web3j.abi.datatypes.generated.Bytes32;
import org.web3j.abi.datatypes.generated.Uint256;
import org.web3j.abi.datatypes.generated.Uint8;
import org.web3j.crypto.Credentials;
import org.web3j.protocol.Web3j;
import org.web3j.protocol.core.DefaultBlockParameter;
import org.web3j.protocol.core.RemoteCall;
import org.web3j.protocol.core.RemoteFunctionCall;
import org.web3j.protocol.core.methods.request.EthFilter;
import org.web3j.protocol.core.methods.response.BaseEventResponse;
import org.web3j.protocol.core.methods.response.Log;
import org.web3j.protocol.core.methods.response.TransactionReceipt;
import org.web3j.tx.Contract;
import org.web3j.tx.TransactionManager;
import org.web3j.tx.gas.ContractGasProvider;

/**
 * Web3j wrapper for ChargingEscrow.sol.
 *
 * Renamed ChargingEscrow → ChargingEscrowContract to match EscrowServiceImpl.
 * Fix applied: removed "javax.annotation.processing.Generated" import which
 * does not exist on the compile classpath in Java 17 + Spring Boot 3.x,
 * causing: "package javax.annotation.processing does not exist".
 */
@SuppressWarnings("rawtypes")
public class ChargingEscrowContract extends Contract {

    public static final String BINARY = "";

    private static String librariesLinkedBinary;

    public static final String FUNC_AMOUNT        = "amount";
    public static final String FUNC_BUYER         = "buyer";
    public static final String FUNC_CHARGER       = "charger";
    public static final String FUNC_CREATEDAT     = "createdAt";
    public static final String FUNC_CURRENTSOC    = "currentSoc";
    public static final String FUNC_GOLDENHASH    = "goldenHash";
    public static final String FUNC_OPERATOR      = "operator";
    public static final String FUNC_SESSIONID     = "sessionId";
    public static final String FUNC_SESSIONTIMEOUT= "sessionTimeout";
    public static final String FUNC_STATE         = "state";
    public static final String FUNC_STATIONID     = "stationId";
    public static final String FUNC_TARGETSOC     = "targetSoc";
    public static final String FUNC_DEPOSIT       = "deposit";
    public static final String FUNC_VERIFYSTATION = "verifyStation";
    public static final String FUNC_STARTCHARGING = "startCharging";
    public static final String FUNC_UPDATESOC     = "updateSoc";
    public static final String FUNC_COMPLETESESSION = "completeSession";
    public static final String FUNC_RELEASEFUNDS  = "releaseFunds";
    public static final String FUNC_REFUND        = "refund";
    public static final String FUNC_CANCEL        = "cancel";
    public static final String FUNC_GETSTATE      = "getState";
    public static final String FUNC_GETBALANCE    = "getBalance";

    public static final Event DEPOSITED_EVENT = new Event("Deposited",
            Arrays.<TypeReference<?>>asList(new TypeReference<Address>(true) {}, new TypeReference<Uint256>() {}));
    public static final Event STATIONVERIFIED_EVENT = new Event("StationVerified",
            Arrays.<TypeReference<?>>asList(new TypeReference<Utf8String>() {}, new TypeReference<Bytes32>() {}));
    public static final Event VERIFICATIONFAILED_EVENT = new Event("VerificationFailed",
            Arrays.<TypeReference<?>>asList(new TypeReference<Utf8String>() {}, new TypeReference<Bytes32>() {}, new TypeReference<Bytes32>() {}));
    public static final Event CHARGINGSTARTED_EVENT = new Event("ChargingStarted",
            Arrays.<TypeReference<?>>asList(new TypeReference<Utf8String>() {}, new TypeReference<Uint8>() {}));
    public static final Event SOCUPDATED_EVENT = new Event("SocUpdated",
            Arrays.<TypeReference<?>>asList(new TypeReference<Uint8>() {}, new TypeReference<Uint8>() {}));
    public static final Event SESSIONCOMPLETED_EVENT = new Event("SessionCompleted",
            Arrays.<TypeReference<?>>asList(new TypeReference<Utf8String>() {}, new TypeReference<Uint8>() {}));
    public static final Event FUNDSRELEASED_EVENT = new Event("FundsReleased",
            Arrays.<TypeReference<?>>asList(new TypeReference<Address>(true) {}, new TypeReference<Uint256>() {}));
    public static final Event REFUNDED_EVENT = new Event("Refunded",
            Arrays.<TypeReference<?>>asList(new TypeReference<Address>(true) {}, new TypeReference<Uint256>() {}, new TypeReference<Utf8String>() {}));
    public static final Event CANCELLED_EVENT = new Event("Cancelled",
            Arrays.<TypeReference<?>>asList(new TypeReference<Utf8String>() {}));

    protected static final HashMap<String, String> _addresses;
    static { _addresses = new HashMap<>(); }

    protected ChargingEscrowContract(String contractAddress, Web3j web3j,
            Credentials credentials, ContractGasProvider contractGasProvider) {
        super(BINARY, contractAddress, web3j, credentials, contractGasProvider);
    }

    protected ChargingEscrowContract(String contractAddress, Web3j web3j,
            TransactionManager transactionManager, ContractGasProvider contractGasProvider) {
        super(BINARY, contractAddress, web3j, transactionManager, contractGasProvider);
    }

    public static ChargingEscrowContract load(String contractAddress, Web3j web3j,
            Credentials credentials, ContractGasProvider contractGasProvider) {
        return new ChargingEscrowContract(contractAddress, web3j, credentials, contractGasProvider);
    }

    public static ChargingEscrowContract load(String contractAddress, Web3j web3j,
            TransactionManager transactionManager, ContractGasProvider contractGasProvider) {
        return new ChargingEscrowContract(contractAddress, web3j, transactionManager, contractGasProvider);
    }

    public static RemoteCall<ChargingEscrowContract> deploy(Web3j web3j, Credentials credentials,
            ContractGasProvider contractGasProvider, String _operator, String _charger,
            String _stationId, byte[] _goldenHash, BigInteger _targetSoc, BigInteger _sessionTimeout) {
        String encodedConstructor = FunctionEncoder.encodeConstructor(Arrays.<Type>asList(
                new org.web3j.abi.datatypes.Address(_operator),
                new org.web3j.abi.datatypes.Address(_charger),
                new org.web3j.abi.datatypes.Utf8String(_stationId),
                new org.web3j.abi.datatypes.generated.Bytes32(_goldenHash),
                new org.web3j.abi.datatypes.generated.Uint8(_targetSoc),
                new org.web3j.abi.datatypes.generated.Uint256(_sessionTimeout)));
        return deployRemoteCall(ChargingEscrowContract.class, web3j, credentials,
                contractGasProvider, getDeploymentBinary(), encodedConstructor);
    }

    public RemoteFunctionCall<TransactionReceipt> deposit(BigInteger weiValue) {
        final Function function = new Function(FUNC_DEPOSIT,
                Arrays.<Type>asList(), Collections.<TypeReference<?>>emptyList());
        return executeRemoteCallTransaction(function, weiValue);
    }

    public RemoteFunctionCall<TransactionReceipt> verifyStation(byte[] liveHash) {
        final Function function = new Function(FUNC_VERIFYSTATION,
                Arrays.<Type>asList(new org.web3j.abi.datatypes.generated.Bytes32(liveHash)),
                Collections.<TypeReference<?>>emptyList());
        return executeRemoteCallTransaction(function);
    }

    public RemoteFunctionCall<TransactionReceipt> startCharging(String _sessionId) {
        final Function function = new Function(FUNC_STARTCHARGING,
                Arrays.<Type>asList(new org.web3j.abi.datatypes.Utf8String(_sessionId)),
                Collections.<TypeReference<?>>emptyList());
        return executeRemoteCallTransaction(function);
    }

    public RemoteFunctionCall<TransactionReceipt> updateSoc(BigInteger soc) {
        final Function function = new Function(FUNC_UPDATESOC,
                Arrays.<Type>asList(new org.web3j.abi.datatypes.generated.Uint8(soc)),
                Collections.<TypeReference<?>>emptyList());
        return executeRemoteCallTransaction(function);
    }

    public RemoteFunctionCall<TransactionReceipt> completeSession() {
        final Function function = new Function(FUNC_COMPLETESESSION,
                Arrays.<Type>asList(), Collections.<TypeReference<?>>emptyList());
        return executeRemoteCallTransaction(function);
    }

    public RemoteFunctionCall<TransactionReceipt> releaseFunds() {
        final Function function = new Function(FUNC_RELEASEFUNDS,
                Arrays.<Type>asList(), Collections.<TypeReference<?>>emptyList());
        return executeRemoteCallTransaction(function);
    }

    public RemoteFunctionCall<TransactionReceipt> refund(String reason) {
        final Function function = new Function(FUNC_REFUND,
                Arrays.<Type>asList(new org.web3j.abi.datatypes.Utf8String(reason)),
                Collections.<TypeReference<?>>emptyList());
        return executeRemoteCallTransaction(function);
    }

    public RemoteFunctionCall<TransactionReceipt> cancel(String reason) {
        final Function function = new Function(FUNC_CANCEL,
                Arrays.<Type>asList(new org.web3j.abi.datatypes.Utf8String(reason)),
                Collections.<TypeReference<?>>emptyList());
        return executeRemoteCallTransaction(function);
    }

    public RemoteFunctionCall<BigInteger> getState() {
        final Function function = new Function(FUNC_GETSTATE,
                Arrays.<Type>asList(),
                Arrays.<TypeReference<?>>asList(new TypeReference<Uint8>() {}));
        return executeRemoteCallSingleValueReturn(function, BigInteger.class);
    }

    public RemoteFunctionCall<BigInteger> getBalance() {
        final Function function = new Function(FUNC_GETBALANCE,
                Arrays.<Type>asList(),
                Arrays.<TypeReference<?>>asList(new TypeReference<Uint256>() {}));
        return executeRemoteCallSingleValueReturn(function, BigInteger.class);
    }

    public RemoteFunctionCall<BigInteger> amount() {
        final Function function = new Function(FUNC_AMOUNT,
                Arrays.<Type>asList(),
                Arrays.<TypeReference<?>>asList(new TypeReference<Uint256>() {}));
        return executeRemoteCallSingleValueReturn(function, BigInteger.class);
    }

    public RemoteFunctionCall<BigInteger> currentSoc() {
        final Function function = new Function(FUNC_CURRENTSOC,
                Arrays.<Type>asList(),
                Arrays.<TypeReference<?>>asList(new TypeReference<Uint8>() {}));
        return executeRemoteCallSingleValueReturn(function, BigInteger.class);
    }

    private static String getDeploymentBinary() {
        return librariesLinkedBinary != null ? librariesLinkedBinary : BINARY;
    }

    protected String getStaticDeployedAddress(String networkId) { return _addresses.get(networkId); }
    public static String getPreviouslyDeployedAddress(String networkId) { return _addresses.get(networkId); }

    // ── Event response classes ────────────────────────────────────────────────
    public static class DepositedEventResponse extends BaseEventResponse { public String buyer; public BigInteger amount; }
    public static class StationVerifiedEventResponse extends BaseEventResponse { public String stationId; public byte[] liveHash; }
    public static class VerificationFailedEventResponse extends BaseEventResponse { public String stationId; public byte[] liveHash; public byte[] goldenHash; }
    public static class ChargingStartedEventResponse extends BaseEventResponse { public String sessionId; public BigInteger targetSoc; }
    public static class SocUpdatedEventResponse extends BaseEventResponse { public BigInteger previousSoc; public BigInteger currentSoc; }
    public static class SessionCompletedEventResponse extends BaseEventResponse { public String sessionId; public BigInteger finalSoc; }
    public static class FundsReleasedEventResponse extends BaseEventResponse { public String charger; public BigInteger amount; }
    public static class RefundedEventResponse extends BaseEventResponse { public String buyer; public BigInteger amount; public String reason; }
    public static class CancelledEventResponse extends BaseEventResponse { public String reason; }
}